mapper.select:
SELECT TDS.ID, TDS.SCN, TDSI.ID SHIPVOYAGE_ITEM_ID, TDSI.COMPANY_NAME, TDSI.COMPANY_ID, CONCAT(CONCAT(TDS.SHIP_NAME, '_'), TDSI.VOYAGE) SHIP_NAME, TDS.SHIP_NAME SHIP_NAME_EXPORT, TDSI.VOYAGE, TDSI.TRADE_TYPE, TDSI.LOAD_UNLOAD, TDSI.CUSTOMER_NAME, TDSI.CUSTOMER_ID, MS.NET_WEIGHT, TDS.BERTH_TIME, TDS.LEAVE_BERTH_TIME, CEIL(TDS.LEAVE_BERTH_TIME - TDS.BERTH_TIME) BERTH_DAYS, t_c_s_tmp.STATEMENT_NO STATEMENT_NO, t_c_ship_tmp.amount AMOUNT, t_c_ship_tmp.CREATE_BY_NAME CREATE_BY_NAME, t_c_ship_tmp.CREATE_TIME CREATE_TIME, TDS.BERTH_NAME, TDS.ARRIVAL_ANCHORAGE_TIME, CEIL(TDS.LEAVE_ANCHORAGE_TIME - TDS.ARRIVAL_ANCHORAGE_TIME) ANCHORAGE_DAYS, t_f_work_times.times TINGGONG_FUGONG_TIMES, TDS.SHIP_STATUS_CODE, MDD.DICT_LABEL AS WORK_AREA_CD FROM T_DIS_SHIPVOYAGE_ITEM TDSI JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID JOIN M_SHIP MS ON TDS.SHIP_ID = MS.ID LEFT JOIN M_BERTH MB ON TDS.BERTH_ID = MB.ID LEFT JOIN M_DICT_DATA MDD ON MDD.DICT_TYPE = 'WORK_AREA' AND MDD.DICT_VALUE = MB.WORK_AREA_CD left join (SELECT SHIPVOYAGE_ID,LISTAGG(TO_CHAR(TDSD.DYNAMIC_START_TIME, 'YYYY-MM-DD HH24:MI:SS'), ',') WITHIN GROUP ( ORDER BY TDSD.CREATE_TIME ) times FROM T_DIS_SHIP_DYNAMIC TDSD WHERE TDSD.DYNAMIC_TYPE_CODE IN ('80', '90') group by TDSD.SHIPVOYAGE_ID) t_f_work_times on t_f_work_times.SHIPVOYAGE_ID= TDS.ID
left join (SELECT CREATE_TIME,CREATE_BY_NAME,SUM(AMOUNT) amount,SHIPVOYAGE_ID,SHIPVOYAGE_ITEM_ID FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '10' group by CREATE_TIME, CREATE_BY_NAME,SHIPVOYAGE_ID,SHIPVOYAGE_ITEM_ID ) t_c_ship_tmp on t_c_ship_tmp.SHIPVOYAGE_ITEM_ID = TDSI.ID left join (SELECT STATEMENT_NO,SHIPVOYAGE_ID,SHIPVOYAGE_ITEM_ID FROM T_COST_STATEMENT TCS WHERE TCS."TYPE" = '30' and ROWNUM = 1) t_c_s_tmp on t_c_s_tmp.SHIPVOYAGE_ITEM_ID = TDSI.ID
(TDS.BERTHING_CHARGE is null OR TDS.BERTHING_CHARGE = '1') AND MDD.DICT_LABEL is not null AND (TDS.WHARF IS NULL OR TDS.WHARF = '1') and (TDSI.IS_BERTHAGE != '0')
AND TDSI.ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TDSI.COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND TDS.ID = #{shipvoyagId,jdbcType=BIGINT}
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
AND TDSI.CUSTOMER_ID = #{customerId,jdbcType=BIGINT}
AND TDS.SCN LIKE #{scnLike,jdbcType=VARCHAR}
AND TDS.SHIP_STATUS_CODE != '120'
AND TDS.SHIP_STATUS_CODE = '120'
AND TDS.LEAVE_BERTH_TIME >= #{beginLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_BERTH_TIME <= #{endLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}
AND TDSI.ID
NOT
IN (SELECT TCS.SHIPVOYAGE_ITEM_ID FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '10' AND TCS.SHIPVOYAGE_ITEM_ID IS NOT NULL
AND TCS.STATUS =#{status,jdbcType=VARCHAR}
AND TCS.ID NOT IN ( SELECT TCSD.BUSINESS_ID FROM T_COST_STATEMENT TCST INNER JOIN T_COST_STATEMENT_DETAIL TCSD ON TCST.ID = TCSD.STATEMENT WHERE TCST.STATUS IN ('40','50') AND TCSD.BUSINESS_ID IS NOT NULL )
)
AND TDSI.ID IN ( SELECT TCST.SHIPVOYAGE_ITEM_ID FROM T_COST_STATEMENT TCST INNER JOIN T_COST_STATEMENT_DETAIL TCSD ON TCST.ID = TCSD.STATEMENT INNER JOIN T_COST_SHIP TCS ON TCSD.BUSINESS_ID = TCS.ID WHERE TCS.TYPE = '10' AND TCST.STATUS = #{status,jdbcType=VARCHAR} )
AND MB.WORK_AREA_CD = #{workAreaCd,jdbcType=VARCHAR}
AND MB.WORK_AREA_CD = '02'
AND (MB.WORK_AREA_CD = '01' OR MB.WORK_AREA_CD = '03')
ORDER BY LEAVE_PORT_TIME DESC

mapper.update:
UPDATE T_COST_SHIP
SET STATUS = #{status,jdbcType=VARCHAR}
WHERE SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TYPE = '10'

