SELECT  ID,SHIPVOYAGE_ID,DYNAMIC_TYPE_CODE,SHIPVOYAGE_ITEM_ID,DYNAMIC_START_TIME FROM T_DIS_SHIP_DYNAMIC
WHERE
  DYNAMIC_TYPE_CODE IN  (110,50)
  AND SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
  AND SHIPVOYAGE_ID =#{shipvoyageId,jdbcType=BIGINT}
    ORDER BY DYNAMIC_START_TIME
